#include <stdint.h>
#include "uart.h"
#include "dht11.h"
#include "display.h"

int main(void)
{
     *pAHB1ENR |= (1<<0);

 TIM2_Init();

 UART2_Init(115200);

 DHT11_Data sensor;

    while(1)
    {
    	if(DHT11_ReadData(&sensor))
    	{
    		DisplaySensorData(&sensor);
    	    delay_ms(1000);
    	}


    }

}













